from django import forms
from django.core.exceptions import ValidationError
from datetime import date


class ReservationStep2Form(forms.Form):
    nombre = forms.CharField(
        max_length=120,
        required=True,
        widget=forms.TextInput(attrs={
            'class': 'form-control',
            'placeholder': 'Nombre completo'
        })
    )
    email = forms.EmailField(
        required=True,
        widget=forms.EmailInput(attrs={
            'class': 'form-control',
            'placeholder': 'Correo electrónico'
        })
    )
    telefono = forms.CharField(
        max_length=20,
        required=False,
        widget=forms.TextInput(attrs={
            'class': 'form-control',
            'placeholder': 'Teléfono (opcional)'
        })
    )

    def clean_nombre(self):
        nombre = self.cleaned_data.get('nombre', '').strip()
        if not nombre:
            raise ValidationError('El nombre es obligatorio.')
        if len(nombre) < 3:
            raise ValidationError('El nombre debe tener al menos 3 caracteres.')
        return nombre

    def clean_email(self):
        email = self.cleaned_data.get('email', '').strip()
        if not email:
            raise ValidationError('El correo es obligatorio.')
        return email

    def clean_telefono(self):
        telefono = self.cleaned_data.get('telefono', '').strip()
        if telefono and len(telefono) < 7:
            raise ValidationError('El teléfono debe tener al menos 7 caracteres.')
        return telefono

from decimal import Decimal
from django.conf import settings


class PayPalService:
    """
    Servicio para integración con PayPal Sandbox.
    """

    def __init__(self):
        self.sandbox_mode = settings.PAYPAL_SANDBOX_MODE
        self.client_id = settings.PAYPAL_CLIENT_ID
        self.client_secret = settings.PAYPAL_CLIENT_SECRET

        if self.sandbox_mode:
            self.base_url = 'https://sandbox.paypal.com'
        else:
            self.base_url = 'https://www.paypal.com'

    def crear_pago(self, reserva):
        """
        Crea un pago en PayPal para una reserva.
        En esta versión simplificada, retorna un diccionario con los datos.
        """
        return {
            'status': 'created',
            'reserva_id': reserva.id,
            'importe': str(reserva.importe_total),
            'moneda': 'EUR',
        }

    def verificar_pago(self, transaction_id):
        """
        Verifica el estado de un pago en PayPal.
        """
        return {
            'status': 'verified',
            'transaction_id': transaction_id,
        }

from django.shortcuts import render, redirect, get_object_or_404
from django.views.decorators.http import require_http_methods
from django.contrib import messages
from django.contrib.auth.decorators import login_required
from django.http import JsonResponse
from django.db import transaction
from datetime import datetime
from decimal import Decimal
import uuid

from .models import Cesta, ItemCesta, Reserva, ItemReserva
from .forms import ReservationStep2Form
from .services.pricing import calcular_precio_item, calcular_tasa_combustible
from .services.email import enviar_confirmacion_reserva
from catalog.models import Barco


def get_or_create_cart(request):
    """
    Obtiene o crea la cesta del usuario.
    Si está autenticado, usa su usuario.
    Si no, usa la session_key.
    """
    if request.user.is_authenticated:
        cesta, created = Cesta.objects.get_or_create(usuario=request.user)
    else:
        session_key = request.session.session_key
        if not session_key:
            request.session.create()
            session_key = request.session.session_key
        cesta, created = Cesta.objects.get_or_create(session_key=session_key)
    return cesta


def clear_cart_for_admin(request):
    """
    Vacía la cesta si el usuario es administrador.
    """
    if request.user.is_authenticated and request.user.is_staff:
        cesta = get_or_create_cart(request)
        cesta.items.all().delete()


@require_http_methods(["GET"])
def cart(request):
    """
    Vista de la cesta de compras.
    """
    clear_cart_for_admin(request)

    cesta = get_or_create_cart(request)
    items = cesta.items.all()
    total = Decimal('0.00')

    for item in items:
        dias = (item.fecha_fin - item.fecha_inicio).days
        if dias < 1:
            dias = 1
        precio_base, tasa_combustible, item_total = calcular_precio_item(
            item.barco, item.cantidad, dias
        )
        item.precio_base = precio_base
        item.tasa_combustible = tasa_combustible
        item.subtotal = item_total
        total += item_total

    context = {
        'cesta': cesta,
        'items': items,
        'total': total,
    }
    return render(request, 'reservations/cart.html', context)


@require_http_methods(["POST"])
def add_to_cart(request):
    """
    Añade un barco a la cesta.
    """
    if request.user.is_authenticated and request.user.is_staff:
        messages.error(request, 'Los administradores no pueden añadir barcos a la cesta.')
        return redirect('catalog:barco_list')

    cesta = get_or_create_cart(request)

    barco_id = request.POST.get('barco_id')
    cantidad = request.POST.get('cantidad', 1)
    fecha_inicio = request.POST.get('fecha_inicio')
    fecha_fin = request.POST.get('fecha_fin')

    try:
        barco = Barco.objects.get(id=barco_id, activo=True)
        cantidad = int(cantidad)

        if cantidad < 1:
            messages.error(request, 'La cantidad debe ser mayor a 0.')
            return redirect('catalog:barco_detail', id=barco_id)

        if cantidad > barco.cantidad_disponible:
            messages.error(request, f'Solo hay {barco.cantidad_disponible} unidades disponibles.')
            return redirect('catalog:barco_detail', id=barco_id)

        fecha_inicio_obj = datetime.strptime(fecha_inicio, '%Y-%m-%d').date()
        fecha_fin_obj = datetime.strptime(fecha_fin, '%Y-%m-%d').date()

        if fecha_inicio_obj >= fecha_fin_obj:
            messages.error(request, 'La fecha de inicio debe ser anterior a la fecha de fin.')
            return redirect('catalog:barco_detail', id=barco_id)

        item, created = ItemCesta.objects.get_or_create(
            cesta=cesta,
            barco=barco,
            fecha_inicio=fecha_inicio_obj,
            fecha_fin=fecha_fin_obj,
            defaults={'cantidad': cantidad}
        )

        if not created:
            item.cantidad += cantidad
            item.save()

        messages.success(request, f'{barco.nombre} añadido a la cesta.')
        return redirect('reservations:cart')

    except Barco.DoesNotExist:
        messages.error(request, 'El barco no existe.')
        return redirect('catalog:barco_list')
    except (ValueError, TypeError):
        messages.error(request, 'Datos inválidos.')
        return redirect('catalog:barco_list')


@require_http_methods(["POST"])
def update_cart(request):
    """
    Actualiza la cantidad de un item en la cesta.
    """
    cesta = get_or_create_cart(request)
    item_id = request.POST.get('item_id')
    cantidad = request.POST.get('cantidad')

    try:
        item = ItemCesta.objects.get(id=item_id, cesta=cesta)
        cantidad = int(cantidad)

        if cantidad < 1:
            item.delete()
            messages.success(request, 'Item eliminado de la cesta.')
        else:
            if cantidad > item.barco.cantidad_disponible:
                messages.error(request, f'Solo hay {item.barco.cantidad_disponible} unidades disponibles.')
            else:
                item.cantidad = cantidad
                item.save()
                messages.success(request, 'Cesta actualizada.')
    except ItemCesta.DoesNotExist:
        messages.error(request, 'Item no encontrado.')
    except (ValueError, TypeError):
        messages.error(request, 'Cantidad inválida.')

    return redirect('reservations:cart')


@require_http_methods(["POST"])
def clear_cart(request):
    """
    Vacía la cesta completamente.
    """
    cesta = get_or_create_cart(request)
    cesta.items.all().delete()
    messages.success(request, 'Cesta vaciada.')
    return redirect('reservations:cart')


@require_http_methods(["GET", "POST"])
def step1(request):
    """
    Paso 1 de la reserva: Confirmación de artículos.
    """
    cesta = get_or_create_cart(request)
    items = cesta.items.all()

    if not items.exists():
        messages.error(request, 'La cesta está vacía.')
        return redirect('reservations:cart')

    if request.method == 'POST':
        request.session['reserva_datos'] = {
            'paso': 1,
            'fecha_creacion': datetime.now().isoformat(),
        }
        request.session.modified = True
        return redirect('reservations:step2')

    total = Decimal('0.00')
    for item in items:
        dias = (item.fecha_fin - item.fecha_inicio).days
        if dias < 1:
            dias = 1
        precio_base, tasa_combustible, item_total = calcular_precio_item(
            item.barco, item.cantidad, dias
        )
        item.precio_base = precio_base
        item.tasa_combustible = tasa_combustible
        item.subtotal = item_total
        total += item_total

    context = {
        'items': items,
        'total': total,
    }
    return render(request, 'reservations/step1.html', context)


@require_http_methods(["GET", "POST"])
def step2(request):
    """
    Paso 2 de la reserva: Datos del cliente.
    """
    if 'reserva_datos' not in request.session:
        messages.error(request, 'Debe completar el paso 1 primero.')
        return redirect('reservations:step1')

    cesta = get_or_create_cart(request)
    items = cesta.items.all()

    if not items.exists():
        messages.error(request, 'La cesta está vacía.')
        return redirect('reservations:cart')

    if request.method == 'POST':
        form = ReservationStep2Form(request.POST)
        if form.is_valid():
            request.session['reserva_datos']['nombre'] = form.cleaned_data['nombre']
            request.session['reserva_datos']['email'] = form.cleaned_data['email']
            request.session['reserva_datos']['telefono'] = form.cleaned_data['telefono']
            request.session.modified = True
            return redirect('reservations:step3')
    else:
        form = ReservationStep2Form()

    usuario_nombre = ''
    usuario_email = ''
    if request.user.is_authenticated:
        usuario_nombre = request.user.get_full_name() or request.user.email
        usuario_email = request.user.email

    context = {
        'form': form,
        'usuario_nombre': usuario_nombre,
        'usuario_email': usuario_email,
    }
    return render(request, 'reservations/step2.html', context)


@require_http_methods(["GET", "POST"])
def step3(request):
    """
    Paso 3 de la reserva: Método de pago.
    """
    if 'reserva_datos' not in request.session or 'nombre' not in request.session.get('reserva_datos', {}):
        messages.error(request, 'Debe completar los pasos anteriores primero.')
        return redirect('reservations:step1')

    cesta = get_or_create_cart(request)
    items = cesta.items.all()

    if not items.exists():
        messages.error(request, 'La cesta está vacía.')
        return redirect('reservations:cart')

    if request.method == 'POST':
        metodo_pago = request.POST.get('metodo_pago')

        if metodo_pago not in ['PAYPAL', 'CONTRA_REEMBOLSO']:
            messages.error(request, 'Método de pago inválido.')
        else:
            request.session['reserva_datos']['metodo_pago'] = metodo_pago
            request.session.modified = True
            return redirect('reservations:confirmation')

    context = {
        'metodos_pago': ['PAYPAL', 'CONTRA_REEMBOLSO'],
    }
    return render(request, 'reservations/step3.html', context)


@require_http_methods(["GET"])
def confirmation(request):
    """
    Confirmación de la reserva y creación en base de datos.
    """
    if 'reserva_datos' not in request.session or 'metodo_pago' not in request.session.get('reserva_datos', {}):
        messages.error(request, 'Debe completar todos los pasos primero.')
        return redirect('reservations:step1')

    cesta = get_or_create_cart(request)
    items = cesta.items.all()

    if not items.exists():
        messages.error(request, 'La cesta está vacía.')
        return redirect('reservations:cart')

    reserva_datos = request.session.get('reserva_datos', {})

    # Crear la reserva dentro de una transacción
    with transaction.atomic():
        codigo_seguimiento = str(uuid.uuid4())[:32]

        total = Decimal('0.00')
        importe_combustible_total = Decimal('0.00')
        fecha_inicio = None
        fecha_fin = None

        for item in items:
            dias = (item.fecha_fin - item.fecha_inicio).days
            if dias < 1:
                dias = 1
            precio_base, tasa_combustible, item_total = calcular_precio_item(
                item.barco, item.cantidad, dias
            )
            total += precio_base
            importe_combustible_total += tasa_combustible

            if not fecha_inicio or item.fecha_inicio < fecha_inicio:
                fecha_inicio = item.fecha_inicio
            if not fecha_fin or item.fecha_fin > fecha_fin:
                fecha_fin = item.fecha_fin

        importe_total = total + importe_combustible_total

        reserva = Reserva.objects.create(
            codigo_seguimiento=codigo_seguimiento,
            cliente=request.user if request.user.is_authenticated else None,
            nombre_cliente=reserva_datos.get('nombre', ''),
            email_cliente=reserva_datos.get('email', ''),
            telefono_cliente=reserva_datos.get('telefono', ''),
            estado='PENDIENTE_DE_PAGO',
            metodo_pago=reserva_datos.get('metodo_pago', ''),
            importe_total=importe_total,
            importe_combustible=importe_combustible_total,
            fecha_inicio=fecha_inicio,
            fecha_fin=fecha_fin,
        )

        for item in items:
            dias = (item.fecha_fin - item.fecha_inicio).days
            if dias < 1:
                dias = 1
            tasa_dia = calcular_tasa_combustible(item.barco, 1)

            ItemReserva.objects.create(
                reserva=reserva,
                barco=item.barco,
                cantidad=item.cantidad,
                precio_unitario=item.barco.precio_dia,
                tasa_combustible_dia=tasa_dia,
            )

        # Vaciar la cesta
        cesta.items.all().delete()

        # Enviar correo de confirmación
        enviar_confirmacion_reserva(reserva)

    # Limpiar sesión
    if 'reserva_datos' in request.session:
        del request.session['reserva_datos']
    request.session.modified = True

    context = {
        'reserva': reserva,
    }
    return render(request, 'reservations/confirmation.html', context)


@require_http_methods(["POST"])
def cancel_reservation(request, codigo):
    """
    Cancela una reserva si está en estado PENDIENTE_DE_PAGO.
    """
    reserva = get_object_or_404(Reserva, codigo_seguimiento=codigo)

    if reserva.estado in ['EN_USO', 'DEVUELTO']:
        messages.error(request, 'No se puede cancelar una reserva en uso o devuelta.')
    elif reserva.estado == 'CANCELADA':
        messages.info(request, 'Esta reserva ya ha sido cancelada.')
    else:
        reserva.estado = 'CANCELADA'
        reserva.save()
        messages.success(request, 'Reserva cancelada correctamente.')

    return redirect('tracking:detail', codigo=codigo)

{% extends 'base.html' %}

{% block title %}Reserva - Paso 2 - Hundidos{% endblock %}

{% block content %}
<h2>Reserva - Paso 2: Datos del Cliente</h2>

<form method="post" style="max-width: 600px; margin: 40px auto;">
    {% csrf_token %}

    <div class="form-group">
        <label for="{{ form.nombre.id_for_label }}">{{ form.nombre.label }}:</label>
        {{ form.nombre }}
        {% if form.nombre.errors %}
            <div style="color: red; font-size: 12px; margin-top: 5px;">
                {% for error in form.nombre.errors %}
                    <p>{{ error }}</p>
                {% endfor %}
            </div>
        {% endif %}
    </div>

    <div class="form-group">
        <label for="{{ form.email.id_for_label }}">{{ form.email.label }}:</label>
        {{ form.email }}
        {% if form.email.errors %}
            <div style="color: red; font-size: 12px; margin-top: 5px;">
                {% for error in form.email.errors %}
                    <p>{{ error }}</p>
                {% endfor %}
            </div>
        {% endif %}
    </div>

    <div class="form-group">
        <label for="{{ form.telefono.id_for_label }}">{{ form.telefono.label }}:</label>
        {{ form.telefono }}
        {% if form.telefono.errors %}
            <div style="color: red; font-size: 12px; margin-top: 5px;">
                {% for error in form.telefono.errors %}
                    <p>{{ error }}</p>
                {% endfor %}
            </div>
        {% endif %}
    </div>

    {% if user.is_authenticated %}
        <div style="background-color: #d1ecf1; color: #0c5460; padding: 15px; border-radius: 4px; margin-bottom: 20px; border: 1px solid #bee5eb;">
            <p><strong>Nota:</strong> Los datos de tu cuenta registrada se han rellenado automáticamente. Puedes modificarlos si es necesario.</p>
        </div>
    {% endif %}

